"use client";

/**
 * Opener for the `whatsappShellWindow` overlay.
 *
 * - `useOpenWhatsAppShellWindow()` — imperative hook. Call to open with typed options;
 *   returns a handle with a `close()` method.
 * - `<WhatsAppShellWindowController />` — declarative wrapper. Mount to open,
 *   unmount to close. Equivalent ergonomics to rendering a normal component.
 *
 * Generated by scripts/generate-overlay-controller.ts (`openers` mode).
 * Hand-edit freely after the initial seed; the script will not re-emit a
 * file that already exists unless invoked with --force.
 */

import { useCallback, useEffect } from "react";
import { useAppDispatch } from "@/lib/redux/hooks";
import { closeOverlay, openOverlay } from "@/lib/redux/slices/overlaySlice";

const OVERLAY_ID = "whatsappShellWindow" as const;

export interface OpenWhatsAppShellWindowOptions {
  userName?: string;
  userAvatarUrl?: string | null;
}

export interface WhatsAppShellWindowHandle {
  close: () => void;
}

export function useOpenWhatsAppShellWindow() {
  const dispatch = useAppDispatch();
  return useCallback(
    (opts: OpenWhatsAppShellWindowOptions = {}): WhatsAppShellWindowHandle => {
      dispatch(
        openOverlay({
          overlayId: OVERLAY_ID,
          data: {
            userName: opts.userName,
            userAvatarUrl: opts.userAvatarUrl,
          },
        }),
      );
      return {
        close: () => dispatch(closeOverlay({ overlayId: OVERLAY_ID })),
      };
    },
    [dispatch],
  );
}

/**
 * Declarative form. Renders nothing visible; opens the overlay on mount,
 * closes it on unmount. Use this when a caller wants to express overlay
 * state declaratively (the way they'd render a normal component).
 */
export function WhatsAppShellWindowController(props: OpenWhatsAppShellWindowOptions): null {
  const open = useOpenWhatsAppShellWindow();
  useEffect(() => {
    const handle = open(props);
    return () => handle.close();
  }, [open, props.userName, props.userAvatarUrl]);
  return null;
}
